export const fetchEuropePmcArticles = async (
  topic: Topic | string,
  language: 'es' | 'original' = 'original',
  customQuery?: string
): Promise<ResearchUpdate> => {
  try {
    const mainTerm = customQuery || getEPMCTopicQuery(topic);
    const query = customQuery ? `${mainTerm}` : `(${mainTerm}) AND (HAS_ABSTRACT:y) AND (PUB_YEAR:[2024 TO 2026])`;

    const params = new URLSearchParams({
        query: query,
        format: 'json',
        pageSize: '40',
        resultType: 'core',
        sort: 'DATE_DESC'
    });

    const url = `${EPMC_API_BASE}?${params.toString()}`;
    const data = await fetchWithProxyFallback(url);
    const resultList = data.resultList?.result || [];

    if (resultList.length === 0) return { summary: "No results found in Europe PMC.", articles: [] };

    const articles: Article[] = resultList.map(item => {
      const title = item.title || 'Untitled';
      const abstractText = item.abstractText || "";
      const cleanAbstract = abstractText.replace(/<[^>]*>?/gm, '');
      const source = item.journalTitle || 'Europe PMC';
      const date = item.firstPublicationDate || item.pubYear || 'N/A';
      const year = parseInt(item.pubYear, 10) || 0;

      const relevance = calculateBaseClinicalScore(title, cleanAbstract, source, typeof topic === 'string' ? topic : '', 0, year);
      const category = detectArticleCategory(title, cleanAbstract, source);

      let authorsStr = "";
      if (item.authorList && item.authorList.author) {
          const authors = item.authorList.author;
          const names = authors.slice(0, 3).map((a: any) => a.lastName || a.fullName);
          if (authors.length > 3) names.push("et al");
          authorsStr = names.join(", ");
      }

      const isFree = item.isOpenAccess === 'Y' || item.epmcAuthMan === 'Y';
      const link = item.fullTextUrlList?.fullTextUrl?.find((u: any) => u.documentStyle === 'html' || u.documentStyle === 'pdf')?.url || `https://europepmc.org/article/MED/${item.pmid}`;

      return {
        id: `epmc-${item.id}`,
        title: title,
        summary: cleanAbstract || "Abstract not available.",
        source: source,
        authors: authorsStr,
        url: link,
        date: date,
        category: category,
        relevanceScore: relevance,
        topic: typeof topic === 'string' ? topic : 'General',
        isFree: isFree
      };
    });

    return {
      summary: `Europe PMC: ${articles.length} results.`,
      articles: articles
    };
  } catch (error) {
    console.error("Europe PMC Service Error:", error);
    return { summary: "Error fetching Europe PMC", articles: [] };
  }
};

import { ResearchUpdate, Article, Topic } from "../types";
import { getGeneralTopicQuery } from "../utils/searchContexts";
import { calculateBaseClinicalScore } from "../constants/searchConstants";

const CORE_API_BASE = 'https://api.core.ac.uk/v3/search/works';

export const fetchCoreArticles = async (
  topic: Topic | string,
  language: 'es' | 'original' = 'original',
  customQuery?: string,
  apiKey?: string
): Promise<ResearchUpdate> => {
  try {
    const term = customQuery || getGeneralTopicQuery(topic);
    const query = customQuery 
        ? `(${term})` 
        : `(${term}) AND (nephrology OR kidney)`;

    // Check for network connectivity or CORS restrictions before logging errors
    try {
        const headers: HeadersInit = {
            'Content-Type': 'application/json'
        };
        if (apiKey) {
            headers['Authorization'] = `Bearer ${apiKey}`;
        }

        const response = await fetch(CORE_API_BASE, {
            method: 'POST',
            headers: headers,
            body: JSON.stringify({
                q: query,
                limit: 40,
                offset: 0,
                sort: 'publishedDate:desc'
            })
        });

        if (!response.ok) {
            // Silently handle 429/403/500 to avoid console spam for public API limits
            return { summary: "CORE API Limit/Error", articles: [] };
        }

        const data = await response.json();
        const results = data.results || [];

        const articles: Article[] = results.map((item: any) => {
          const title = item.title || 'Untitled';
          const abstract = item.abstract || "No abstract available.";
          const source = item.publisher || 'CORE Repository';
          const date = item.publishedDate ? item.publishedDate.substring(0, 4) : 'N/A';
          const year = item.yearPublished || 0;

          const relevance = calculateBaseClinicalScore(title, abstract, source, typeof topic === 'string' ? topic : '', 0, year);

          let authorsStr = "";
          if (item.authors && item.authors.length > 0) {
              authorsStr = item.authors.map((a: any) => a.name).slice(0,3).join(', ');
          }

          const link = item.downloadUrl || item.fullTextIdentifier || `https://core.ac.uk/display/${item.id}`;

          return {
            id: `core-${item.id}`,
            title: title,
            summary: abstract,
            source: source,
            authors: authorsStr,
            url: link,
            date: date,
            category: 'Research',
            relevanceScore: relevance,
            topic: typeof topic === 'string' ? topic : 'General',
            isFree: true
          };
        });

        return {
          summary: `CORE: ${articles.length} OA results.`,
          articles: articles
        };

    } catch (networkError) {
        // Catch CORS or Offline errors
        // console.debug("CORE API Network/CORS Error - ignoring.");
        return { summary: "CORE unavailable", articles: [] };
    }

  } catch (error) {
    console.warn("CORE Service Error:", error);
    return { summary: "Error fetching CORE", articles: [] };
  }
};

import { ResearchUpdate, Article, Topic } from "../types";
import { getGeneralTopicQuery } from "../utils/searchContexts";
import { calculateBaseClinicalScore } from "../constants/searchConstants";

// API v2 is required for standard medical terms search
const DOAJ_API_BASE = 'https://doaj.org/api/v2/search/articles';

export const fetchDoajArticles = async (
  topic: Topic | string,
  language: 'es' | 'original' = 'original',
  customQuery?: string
): Promise<ResearchUpdate> => {
  try {
    let term = customQuery || getGeneralTopicQuery(topic);

    // Fix: Remove PubMed-specific date range filters that cause 400 errors in DOAJ API
    term = term.replace(/\s*AND\s*\(?\"\d{4}\"\[Date\s*-\s*Publication\]\s*:\s*\"3000\"\[Date\s*-\s*Publication\]\)?/gi, '');

    // Sanitize: Remove parentheses and clean spaces
    term = term.replace(/[()]/g, '').trim();

    if (!term || term.length < 2) {
        return { summary: "Query too short for DOAJ.", articles: [] };
    }

    // DOAJ path-based search is robust but avoids complex sort fields that cause 400s
    const query = customQuery
        ? `${term}`
        : `${term} nephrology kidney`;

    const url = `${DOAJ_API_BASE}/${encodeURIComponent(query)}?pageSize=40`;

    const response = await fetch(url);

    if (!response.ok) {
        if (response.status === 400) {
            console.debug(`DOAJ API 400 Error. Query: ${query}`);
            return { summary: "DOAJ search parameters adjusted.", articles: [] };
        }
        throw new Error(`DOAJ API Error: ${response.status}`);
    }

    const data = await response.json();
    const results = data.results || [];

    const articles: Article[] = results.map((item: any) => {
      const bib = item.bibjson;
      const title = bib.title || 'Untitled';
      const abstract = bib.abstract || "No abstract available.";
      const source = bib.journal?.title || 'DOAJ Journal';
      const date = bib.year || bib.month || 'N/A';
      const year = bib.year ? parseInt(bib.year, 10) : 0;

      const relevance = calculateBaseClinicalScore(title, abstract, source, typeof topic === 'string' ? topic : '', 0, year);

      let authorsStr = "";
      if (bib.author && bib.author.length > 0) {
          authorsStr = bib.author.map((a: any) => a.name).slice(0,3).join(', ');
      }

      const link = bib.link?.find((l: any) => l.type === 'fulltext')?.url || bib.link?.[0]?.url;

      return {
        id: `doaj-${item.id}`,
        title: title,
        summary: abstract,
        source: source,
        authors: authorsStr,
        url: link,
        date: date,
        category: 'Research',
        relevanceScore: relevance,
        topic: typeof topic === 'string' ? topic : 'General',
        isFree: true 
      };
    });

    return {
      summary: `DOAJ: ${articles.length} OA results.`,
      articles: articles
    };

  } catch (error) {
    console.debug("DOAJ Service Info:", error);
    return { summary: "Error fetching DOAJ", articles: [] };
  }
};

